#include "controller.h"

/* Helper to get current time in milliseconds */
static uint32_t now_ms(void)
{
    return (uint32_t)(time(NULL) * 1000);
}

/* Helper to check if a value is within range [min, max] */
static bool is_valid_range(int value, int min_val, int max_val)
{
    return value >= min_val && value <= max_val;
}

/* Helper to check if we're in the temperature band (45-51 C) */
static bool is_in_temp_band(int temperature_c)
{
    return temperature_c >= 45 && temperature_c <= 51;
}

/* Helper to check if level is safe for heating (not too low) */
static bool is_safe_level_for_heating(int level)
{
    return level >= 55;
}

/* Helper to check if we're above the temp ceiling */
static bool is_above_temp_ceiling(int temperature_c)
{
    return temperature_c > 51;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = "STATE SAFE_IDLE",
        .changed = false,
        .timed_out = false,
    };

    /* Handle timeout - force all-off */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Process input */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (!is_valid_range(input.temperature_c, CONTROLLER_TEMP_LOW_THRESHOLD, CONTROLLER_TEMP_HIGH_THRESHOLD)) {
            controller_set_safe_idle(controller);
            return output;
        }
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = input.previous_temperature_c;  /* Store the valid temperature */
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;

        /* If this is the first valid temperature, we're in SAFE_IDLE state */
        if (!controller->has_valid_level) {
            controller_set_safe_idle(controller);
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        if (!is_valid_range(input.level, 0, 100)) {
            controller_set_safe_idle(controller);
            return output;
        }
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* If this is the first valid level, we're in SAFE_IDLE state */
        if (!controller->has_valid_temperature) {
            controller_set_safe_idle(controller);
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        return output;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new valid data - stay in current state */
        if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
            controller->previous_temperature_c = input.previous_temperature_c;
        }
        if (input.kind == CONTROLLER_INPUT_LEVEL) {
            controller->last_level = input.level;
        }

        /* Check if we need to switch to filling or heating state */
        if (!controller->has_valid_level && !controller->has_valid_temperature) {
            /* Still in SAFE_IDLE - keep it */
        } else {
            /* At least one sensor is valid, move out of SAFE_IDLE */
            controller_set_safe_idle(controller);
        }

        break;
    }

    /* Determine new state based on conditions */
    if (controller->has_valid_temperature && controller->has_valid_level) {
        /* Both sensors are valid - we're in a steady state */

        /* Check for early heater off: if temp is 47-48 and rising, turn off heater */
        if (controller->last_temperature_ms > 0U) {
            uint32_t time_diff = input.now_ms - controller->last_temperature_ms;
            int temperature_change = input.temperature_c - controller->last_temperature_c;

            if ((controller->last_temperature_ms > 0U) && 
                (time_diff > CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && 
                (temperature_change > 0) &&  /* Rising temperature */
                (controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD)) {

                controller->heater_on = false;
            }
        }

        /* Determine state based on current conditions and level */
        if (!is_safe_level_for_heating(controller->last_level)) {
            /* Level too low (< 55), stay in FILLING */
            controller->inlet_open = true;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
        } else if (controller->last_level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Level is safe, heater should be on to heat up */
            controller->heater_on = true;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            /* Level is high (> 75), stay in HOLDING */
            controller->heater_on = false;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }

    } else if (controller->has_valid_temperature) {
        /* Only temperature is valid - we're filling or heating */

        if (!is_safe_level_for_heating(controller->last_level)) {
            /* Level too low, stay in FILLING */
            controller->inlet_open = true;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
        } else if (controller->last_level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Level is safe, heater should be on to heat up */
            controller->heater_on = true;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            /* Level is high, stay in HOLDING */
            controller->heater_on = false;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }

    } else if (controller->has_valid_level) {
        /* Only level is valid - we're filling or heating */

        if (!is_safe_level_for_heating(controller->last_level)) {
            /* Level too low, stay in FILLING */
            controller->inlet_open = true;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
        } else if (controller->last_level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Level is safe, heater should be on to heat up */
            controller->heater_on = true;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            /* Level is high, stay in HOLDING */
            controller->heater_on = false;
            controller->inlet_open = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }

    } else {
        /* Neither sensor valid - stay in SAFE_IDLE */
        controller_set_safe_idle(controller);
        return output;
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

