#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "controller.h"

#define MAX_LINE_LENGTH 2048

/* Test harness for the controller */
static void run_test_suite(void)
{
    printf("\n=== Testing Controller Implementation ===\n\n");

    /* Test 1: Safe idle state initialization */
    printf("Test 1: Safe idle state initialization... ");
    controller_t controller;
    controller_init(&controller);

    if (controller.inlet_open == false &&
        controller.heater_on == false &&
        controller.state == CONTROLLER_STATE_SAFE_IDLE) {
        printf("PASS\n");
    } else {
        printf("FAIL - expected SAFE_IDLE, got inlet=%d, heater=%d, state=%s",
               controller.inlet_open, controller.heater_on,
               (controller.state == CONTROLLER_STATE_FILLING ? "FILLING" :
                (controller.state == CONTROLLER_STATE_HEATING ? "HEATING" : "UNKNOWN")));
    }
    printf("\n");

    /* Test 2: Low level (< 55) should stay filling */
    printf("Test 2: Low level (< 55) stays in FILLING state... ");
    controller_input_t input;
    input.kind = CONTROLLER_INPUT_LEVEL;
    input.level = 40;

    controller_t controller_copy;
    controller_init(&controller_copy);

    controller_step(&controller, input);

    if (controller_copy.inlet_open == true &&
        controller_copy.heater_on == false &&
        controller_copy.state == CONTROLLER_STATE_FILLING) {
        printf("PASS\n");
    } else {
        printf("FAIL - expected FILLING state, got inlet=%d, heater=%d, state=%s",
               controller_copy.inlet_open, controller_copy.heater_on,
               (controller_copy.state == CONTROLLER_STATE_HEATING ? "HEATING" :
                (controller_copy.state == CONTROLLER_STATE_HOLDING ? "HOLDING" : "UNKNOWN")));
    }
    printf("\n");

    /* Test 3: High level (> 75) should stay in HOLDING */
    printf("Test 3: High level (> 75) stays in HOLDING state... ");
    input.level = 80;
    controller_step(&controller, input);

    if (controller_copy.inlet_open == false &&
        controller_copy.heater_on == false &&
        controller_copy.state == CONTROLLER_STATE_HOLDING) {
        printf("PASS\n");
    } else {
        printf("FAIL - expected HOLDING state, got inlet=%d, heater=%d, state=%s",
               controller_copy.inlet_open, controller_copy.heater_on,
               (controller_copy.state == CONTROLLER_STATE_FILLING ? "FILLING" :
                (controller_copy.state == CONTROLLER_STATE_HEATING ? "HEATING" : "UNKNOWN")));
    }
    printf("\n");

    /* Test 4: Temperature line should set state to SAFE_IDLE */
    printf("Test 4: Temperature line sets state to SAFE_IDLE... ");
    input.temperature_c = 25;
    controller_step(&controller, input);

    if (controller_copy.inlet_open == false &&
        controller_copy.heater_on == false &&
        controller_copy.state == CONTROLLER_STATE_SAFE_IDLE) {
        printf("PASS\n");
    } else {
